const test = require("node:test");
const assert = require("node:assert");
const { evaluate } = require("../src/evaluate.js");

test("evaluate dispatches all ops", () => {
  assert.strictEqual(evaluate("+", 2, 3), 5);
  assert.strictEqual(evaluate("-", 9, 4), 5);
  assert.strictEqual(evaluate("*", 2, 6), 12);
});

test("evaluate throws on unknown op", () => {
  assert.throws(() => evaluate("/", 1, 1));
});
